  const entries = await memory.get('conversation');

  for (const entry of entries) {
    if (Date.now() - entry.timestamp > 60 * 60 * 1000) { // 1 hour
      console.warn('Stale memory detected:', entry.id);
      await memory.delete(entry.id);
      return { stale: true, count: entries.length };
    }
  }
  return { fresh: true };
});

