import { createAgent, Middleware } from 'mastra';
import { z } from 'zod';

const validationMiddleware: Middleware = {
  async beforeStep(agent, step, input) {
    const prevStep = agent.workflow.steps[step.index - 1];
    if (prevStep?.outputSchema) {
      const result = prevStep.outputSchema.safeParse(input);
      if (!result.success) {
        throw new Error(`Workflow validation failed: ${result.error.message}`);
      }
    }
    return input;
  }
};

const agent = createAgent({
  middleware: [validationMiddleware],
  workflow: {
    steps: [
      {
        name: 'analyze',
        outputSchema: z.object({ analysis: z.string().min(10) }),
        handler: async () => ({ analysis: 'Valid analysis result' })
      },
      {
        name: 'summarize',
        inputSchema: z.object({ analysis: z.string().min(10) }),
        handler: async (input) => ({ summary: input.analysis })
      }
    ]
  }
});

import { Tool } from 'mastra/tools';
import { z } from 'zod';

function safeTool<T>(tool: Tool, fallback: T): Tool {
  return new Tool({
    ...tool,
    async execute(params) {
      try {
        const result = await tool.execute(params);
        const validation = tool.schema.safeParse(result);

        if (!validation.success) {
          console.warn('Tool validation failed, using fallback');
          return fallback;
        }
        return result;
      } catch (error) {
        console.error('Tool execution failed:', error);
        return fallback;
      }
    }
  });
}

const safeWeatherTool = safeTool(
  weatherTool,
  { temperature: 0, condition: 'unknown' } as any
);

import { Memory } from 'mastra/memory';

class SafeMemory extends Memory {
  async getFresh(key: string, maxAgeMs: number = 60 * 60 * 1000) {
    const entries = await this.get(key);
    const now = Date.now();

    // Filter out stale entries
    const freshEntries = entries.filter(
      entry => now - entry.timestamp < maxAgeMs
    );

    // Cleanup stale entries
    const staleEntries = entries.filter(
      entry => now - entry.timestamp >= maxAgeMs
    );

    for (const stale of staleEntries) {
      await this.delete(stale.id);
    }

    return freshEntries;
  }
}

const safeMemory = new SafeMemory();

// Usage in agent
agent.on('memory:load', async (key) => {
  return await safeMemory.getFresh(key);
});

